args.cypher:
// Traverse the HierarchicalStructures submodel of Hall 4 to find contained entities
MATCH (sm:Submodel {id: 'urn:submodel:hall4:hierarchicalstructures'})-[:HAS_ELEMENT*]->(e:Entity)
RETURN e.idShort, e.entityType, labels(e)

// Find AAS that are in Hall 4, by looking for FacilityInformation or location-related submodels
// First, let's see what AAS exist and their structure
MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
OPTIONAL MATCH (sm)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept)
RETURN aas.idShort, aas.id, sm.idShort, sc.id AS templateSemanticId
ORDER BY aas.idShort

// Find all assets in Hall 4 via the HierarchicalStructures submodel
MATCH (hall:AssetAdministrationShell {idShort: 'Hall4'})-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE sm.idShort = 'HierarchicalStructures'

// Traverse the hierarchy to find all child entities
MATCH (sm)-[:HAS_ELEMENT*]->(node:Entity)

// Find SameAs relationships that point to actual AAS
OPTIONAL MATCH (node)-[:HAS_ELEMENT*]->(sameAs:RelationshipElement)
WHERE sameAs.idShort = 'SameAs'
OPTIONAL MATCH (sameAs)-[:HAS_SECOND]->(target)

// Also get the node's idShort for context
RETURN hall.idShort AS hall, node.idShort AS nodeIdShort, 
       [r in (sameAs)-[:HAS_SECOND]->(t) | t.id] AS targetIds
ORDER BY nodeIdShort

// Traverse the HierarchicalStructures submodel to find all entities and their relationships
MATCH (sm:Submodel {id: 'urn:submodel:hall4:hierarchicalstructures'})-[:HAS_ELEMENT*]->(e:Entity)
RETURN e.idShort AS entityIdShort, e.smId, labels(e) AS labels

// Find submodels related to facility information
MATCH (sm:Submodel)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept {id: 'https://admin-shell.io/dfki/SubmodelTemplate/FacilityInformation/1/0'})
RETURN sm.idShort, sm.id, sc.id AS semanticId

MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE sm HAS_SEMANTIC_ID :SemanticConcept {id: 'https://admin-shell.io/dfki/SubmodelTemplate/FacilityInformation/1/0'}
RETURN aas.idShort, aas.id, sm.idShort, sm.id
